+    expect(updateContentTaskStatus(db, task.id, 'done')).toMatchObject({ status: 'done' });
+    expect(deleteContentTask(db, task.id)).toBe(true);
+    expect(getContentTask(db, task.id)).toBeNull();
+
+    const actions = db
