+
+  it('returns ready when rights, product fields, and tasks are complete', async () => {
+    const product = db
+      .prepare(
+        `INSERT INTO products
+          (sku, title, product_type, price_tax_included, license_summary, operating_environment, refund_policy, status)
+         VALUES
+          (?, ?, ?, ?, ?, ?, ?, ?)`,
+      )
+      .run(
+        'ROUTE-CONTENT-OK',
+        '完成商品',
