+
+  app.patch<{ Body: ProjectPayload; Params: IdParams }>('/api/content/projects/:id/rights', async (req, reply) => {
+    const id = routeId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProject(app.db, id)) {
+      reply.code(404);
+      return { error: 'not_found' };
