+
+  app.delete<{ Params: IdParams }>('/api/content/tasks/:id', async (req, reply) => {
+    const id = routeId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getTask(app.db, id);
+    if (!before) {
+      reply.code(404);
+      return { error: 'not_found' };
