+function assertStatusTransition(from: ContentProjectStatus, to: ContentProjectStatus): void {
+  if (!ALLOWED_TRANSITIONS[from].includes(to)) {
+    throw new Error(`invalid content project status transition: ${from} -> ${to}`);
+  }
