+
+  app.delete<{ Params: IdParams }>('/api/content/projects/:id', async (req, reply) => {
+    const id = routeId(req.params.id);
+    if (id == null) {
+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    const before = getProject(app.db, id);
