+      reply.code(400);
+      return { error: 'invalid_id' };
+    }
+    if (!getProject(app.db, id)) {
+      reply.code(404);
+      return { error: 'not_found' };
+    }
+    try {
+      return updateProject(app.db, id, req.body ?? {});
