+    app.db.transaction(() => {
+      const tasks = listTasksForProject(app.db, id);
+      writeAudit(app.db, { action: 'delete', entityType: PROJECT_ENTITY, entityId: id, before: { ...before, tasks } });
+      app.db.prepare('DELETE FROM content_projects WHERE id = ?').run(id);
+    })();
+    reply.code(204);
